+	// Stop the watchdog
+	store.stopWatchdog()
+
+	// Verify it stopped by checking the done channel is closed
+	select {
+	case <-store.watchdogDone:
+		// Good - channel is closed
+	case <-time.After(2 * time.Second):
+		t.Error("watchdog did not stop within timeout")
+	}
